import os
import redis
from flask import Flask, request, jsonify
from werkzeug.exceptions import BadRequest, Unauthorized

app = Flask(__name__)

# Load environment variables for Redis connection
REDIS_HOST = os.getenv('REDIS_HOST', 'localhost')
REDIS_PORT = int(os.getenv('REDIS_PORT', 6379))
REDIS_PASSWORD = os.getenv('REDIS_PASSWORD', None)
REDIS_TLS = os.getenv('REDIS_TLS', 'true').lower() == 'true'

# Establish a secure connection to the Redis cluster
redis_client = redis.StrictRedis(
    host=REDIS_HOST,
    port=REDIS_PORT,
    password=REDIS_PASSWORD,
    ssl=REDIS_TLS,
    ssl_cert_reqs='required' if REDIS_TLS else None
)

def validate_input(data):
    if not isinstance(data, dict):
        raise BadRequest("Invalid input format")
    for key, value in data.items():
        if not isinstance(key, str) or not isinstance(value, str):
            raise BadRequest("Invalid data types")

@app.route('/store', methods=['POST'])
def store_data():
    try:
        data = request.json
        validate_input(data)
        for key, value in data.items():
            redis_client.setex(key, 3600, value)  # Set TTL to 1 hour
        return jsonify({"status": "success"}), 200
    except BadRequest as e:
        return jsonify({"error": str(e)}), 400
    except Exception as e:
        return jsonify({"error": "Internal Server Error"}), 500

@app.route('/retrieve/<key>', methods=['GET'])
def retrieve_data(key):
    try:
        if not isinstance(key, str):
            raise BadRequest("Invalid key format")
        value = redis_client.get(key)
        if value is None:
            return jsonify({"error": "Key not found"}), 404
        return jsonify({"value": value.decode('utf-8')}), 200
    except BadRequest as e:
        return jsonify({"error": str(e)}), 400
    except Exception as e:
        return jsonify({"error": "Internal Server Error"}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, ssl_context=('cert.pem', 'key.pem'))